-- ============================================================
-- Fase 2 — laudo multilíngue: adiciona coluna idioma à laudo_textos
-- e faz os índices considerarem o idioma. Linhas existentes viram 'pt-BR'.
-- RODAR ANTES do INSERT das linhas EN/ES (senão o índice único bloqueia).
-- ⚠️ Aplicar à mão no Supabase (não roda no Publish).
-- ============================================================

ALTER TABLE public.laudo_textos
  ADD COLUMN IF NOT EXISTS idioma text NOT NULL DEFAULT 'pt-BR';

-- 1 texto PUBLICADO por (tipo, desfecho, bloco, IDIOMA)
DROP INDEX IF EXISTS idx_laudo_textos_unico_publicado;
CREATE UNIQUE INDEX idx_laudo_textos_unico_publicado
  ON public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, idioma)
  WHERE status = 'publicado';

-- índice de leitura passa a incluir idioma
DROP INDEX IF EXISTS idx_laudo_textos_chave;
CREATE INDEX idx_laudo_textos_chave
  ON public.laudo_textos (tipo_consulta, desfecho_clinico, status, idioma);


-- Linhas EN/ES de laudo_textos (geradas). Rodar DEPOIS da migration de idioma.
-- status='publicado' (usável já; especialistas refinam pelo editor).

-- ===== idioma: en-US =====
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$encerramento$LAUDO$, $LAUDO$aborto$LAUDO$, $LAUDO$conclusao$LAUDO$, 1, $LAUDO$Closure conclusion$LAUDO$, $LAUDO$Discontinuation of follow-up after miscarriage. The patient had a diagnosis of gestational diabetes mellitus, treated with nutritional therapy and physical activity, with glycemic control maintained, without the need for insulin.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$encerramento$LAUDO$, $LAUDO$nao_retornou$LAUDO$, $LAUDO$conclusao$LAUDO$, 1, $LAUDO$Closure conclusion$LAUDO$, $LAUDO$Discontinuation due to non-attendance. The patient did not return to continue follow-up of gestational diabetes mellitus. If possible, telephone contact for reassessment is recommended.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$encerramento$LAUDO$, $LAUDO$parto$LAUDO$, $LAUDO$conclusao$LAUDO$, 1, $LAUDO$Closure conclusion$LAUDO$, $LAUDO$Discontinuation of follow-up at delivery. The patient had a diagnosis of gestational diabetes mellitus, treated with nutritional therapy and physical activity, with glycemic control maintained throughout follow-up, without the need for insulin. Responsibility for the pregnant patient remains with the obstetrician.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$2$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Scientific Rationale$LAUDO$, $LAUDO$Over the [dias preenchidos] days of monitoring, [% na meta]% of measurements were within target. According to the GDM treatment protocol in Brazil, adequate control is defined as 70% or more of values within target. In addition, the metabolic indicators (and the ultrasound indicators, when available) are also adequate, confirming that treatment with diet and exercise is being sufficient for glycemic control and, therefore, should be maintained.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$2$LAUDO$, $LAUDO$conduta$LAUDO$, 3, $LAUDO$Recommended Management$LAUDO$, $LAUDO$Maintain the diet, physical activity, and daily 4-point monitoring, without the need for insulin at this time. Reinforce adherence to the meal plan and physical activity. Request an ultrasound to monitor fetal growth and development and amniotic fluid volume. The next follow-up should take place on [data do próximo retorno].
Follow-up interval: 15 days until 30 weeks; from then on, 7 days until delivery.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$3$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Scientific Rationale$LAUDO$, $LAUDO$According to the GDM treatment protocol in Brazil, inadequate control is defined as fewer than 70% of values within target. Only [% na meta]% of glucose readings were within target, below the minimum of 70% recommended. The other metabolic indicators (and ultrasound indicators, when available) are not altered. This indicates that treatment with diet and exercise is insufficient to control hyperglycemia and, therefore, INSULIN must be added.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$3$LAUDO$, $LAUDO$conduta$LAUDO$, 3, $LAUDO$Recommended Management$LAUDO$, $LAUDO$Reinforce the importance of adherence to the prescribed diet and to regular exercise. Start insulin at a dose of [dose total de insulina], subcutaneously: ⅔ in the morning ([dose manhã]) and ⅓ at 10 p.m. / bed time ([dose noite]). Instruct on injection technique, care in the storage and transport of insulin, and signs of hypoglycemia. Prescribe daily 6-point glycemic monitoring — fasting, post-breakfast, pre- and post-lunch, and pre- and post-dinner. The next follow-up should take place on [data do próximo retorno].
Follow-up interval: 7 to 10 days (assess the effects of the introduced insulin).$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$r1_manter$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Scientific Rationale$LAUDO$, $LAUDO$Over the [dias preenchidos] days of monitoring, [% na meta]% of measurements were within target. According to the GDM treatment protocol in Brazil, adequate control is defined as 70% or more of values within target. In addition, the metabolic indicators (and the ultrasound indicators, when available) are also adequate, confirming that treatment with diet and exercise is being sufficient for glycemic control and, therefore, should be maintained.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$r1_manter$LAUDO$, $LAUDO$conduta$LAUDO$, 3, $LAUDO$Recommended Management$LAUDO$, $LAUDO$Maintain the diet, physical activity, and daily 4-point monitoring, without the need for insulin at this time. Reinforce adherence to the meal plan and physical activity. Request an ultrasound to monitor fetal growth and development and amniotic fluid volume. The next follow-up should take place on [data do próximo retorno].
Follow-up interval: 15 days until 30 weeks; from then on, 7 days until delivery.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$r2_insulina$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Scientific Rationale$LAUDO$, $LAUDO$According to the GDM treatment protocol in Brazil, inadequate control is defined as fewer than 70% of values within target. Only [% na meta]% of glucose readings were within target, below the minimum of 70% recommended, with inadequate diet, irregular exercise, and/or excessive maternal weight gain. Given the inadequacy of control, non-adherence, and the absence of an agreement to fully reinforce diet and exercise, the addition of INSULIN is indicated.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$r2_insulina$LAUDO$, $LAUDO$conduta$LAUDO$, 3, $LAUDO$Recommended Management$LAUDO$, $LAUDO$Start insulin therapy at a dose of [dose total de insulina]:
>> 2/3 in the morning: [dose manhã] and
>> 1/3 at 10 p.m. (bed time): [dose noite]
— Both subcutaneously —
Instruct on injection technique, care in the storage and transport of insulin, and signs of hypoglycemia.
Maintain the diet, physical activity, and daily 6-point glycemic monitoring — fasting, pre- and postprandial —, agreeing with the patient on 1-hour or 2-hour postprandial measurement.
Once insulin is introduced, MARI's active follow-up is discontinued.
Responsibility for the pregnant patient remains with the obstetrician (OB), whose obstetric glycemic targets always prevail.
Continued glycemic control may follow three arrangements, at the obstetrician's choice:
(1) the obstetrician themselves manages the dose adjustment, if confident to do so;
(2) collaboration with an endocrinologist, who makes the insulin dose adjustments without taking over the case; or
(3) referral to a specialized service, in the public system.
ATTENTION: Postpartum retesting: perform a 75g OGTT (fasting and 2h) between 6 and 8 weeks after delivery, to reclassify the glycemic status.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$r2_reforcar$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Scientific Rationale$LAUDO$, $LAUDO$According to the GDM treatment protocol in Brazil, inadequate control is defined as fewer than 70% of values within target. Only [% na meta]% of glucose readings were within target, below the minimum of 70% recommended. In addition, there is inadequate diet, irregular exercise, and excessive maternal weight gain. (When possible, from 28 weeks on, add ultrasound indicators — normal EFW/US, AC, and AF, without fetal and/or amniotic fluid compromise.) In this case, there is a chance that full adherence to the recommended treatment — diet + exercise — may still reach the established glycemic targets.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$r2_reforcar$LAUDO$, $LAUDO$conduta$LAUDO$, 3, $LAUDO$Recommended Management$LAUDO$, $LAUDO$Reinforce the importance of the agreement with the pregnant patient regarding adherence to the prescribed diet and to regular exercise, agreeing with her on full adherence. Maintain diet + exercise, with reassessment at a shorter interval. The next follow-up should take place on [data do próximo retorno].
Follow-up interval: 7 to 10 days (assess adherence to diet + exercise).$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$r3_insulina$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Scientific Rationale$LAUDO$, $LAUDO$According to the GDM treatment protocol in Brazil, inadequate control is defined as fewer than 70% of values within target. Only [% na meta]% of glucose readings were within target, below the minimum of 70% recommended. The other metabolic indicators (and ultrasound indicators, when available) are not altered. This indicates that treatment with diet and exercise is insufficient to control hyperglycemia and, therefore, INSULIN must be added.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$r3_insulina$LAUDO$, $LAUDO$conduta$LAUDO$, 3, $LAUDO$Recommended Management$LAUDO$, $LAUDO$Start insulin therapy at a dose of [dose total de insulina]:
>> 2/3 in the morning: [dose manhã] and
>> 1/3 at 10 p.m. (bed time): [dose noite]
— Both subcutaneously —
Instruct on injection technique, care in the storage and transport of insulin, and signs of hypoglycemia.
Maintain the diet, physical activity, and daily 6-point glycemic monitoring — fasting, pre- and postprandial —, agreeing with the patient on 1-hour or 2-hour postprandial measurement.
Once insulin is introduced, MARI's active follow-up is discontinued.
Responsibility for the pregnant patient remains with the obstetrician (OB), whose obstetric glycemic targets always prevail.
Continued glycemic control may follow three arrangements, at the obstetrician's choice:
(1) the obstetrician themselves manages the dose adjustment, if confident to do so;
(2) collaboration with an endocrinologist, who makes the insulin dose adjustments without taking over the case; or
(3) referral to a specialized service, in the public system.
ATTENTION: Postpartum retesting: perform a 75g OGTT (fasting and 2h) between 6 and 8 weeks after delivery, to reclassify the glycemic status.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$r4_reforcar$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Scientific Rationale$LAUDO$, $LAUDO$According to the GDM treatment protocol in Brazil, adequate control is defined as at least 70% of values within target. In this case, [% na meta]% of glucose readings were within target, equal to or above the 70% minimum. However, there is inadequate diet and/or irregular exercise and/or excessive maternal weight gain, and the glucometer memory DOES NOT CONFIRM the reported control. The patient agreed to reinforce full adherence to diet and physical activity; the decision was to reinforce and reassess at a short interval, maintaining the 4-point profile, before adding insulin.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$r4_reforcar$LAUDO$, $LAUDO$conduta$LAUDO$, 3, $LAUDO$Recommended Management$LAUDO$, $LAUDO$Reinforce and agree on full adherence to diet and physical activity. Maintain the daily 4-point glycemic profile and reassess at an earlier follow-up. If, on reassessment, control is confirmed inadequate or there is excessive fetal growth, add insulin at the standardized starting dose (0.5 UI/kg/dia). The next follow-up should occur on [data do próximo retorno].
Follow-up interval: 7 to 10 days.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$r4a_fichae$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Scientific Rationale$LAUDO$, $LAUDO$According to the GDM treatment protocol in Brazil, adequate control is defined as at least 70% of values within target. In this case, [% na meta]% of glucose readings were within target, equal to or above the recommended 70% minimum. However, there is inadequate diet and/or irregular exercise and/or excessive maternal weight gain. The glucometer memory must be evaluated: it CONFIRMS adequate glycemic control — that is, despite adequate control, the patient is not fully adhering to treatment, with possible hyperglycemia peaks not detected in the 4 evaluated points, which represents a risk to the fetus.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$r4a_fichae$LAUDO$, $LAUDO$conduta$LAUDO$, 3, $LAUDO$Recommended Management$LAUDO$, $LAUDO$Recommend a daily 6-point glycemic profile, reinforce and agree on diet + exercise, and reassess with an earlier follow-up.
NOTE —
If a 6-point profile is confirmed adequate, evaluate the fetal growth characteristics.
> If adequate, maintain diet and physical activity and continue monitoring every 7-10 days;
> As soon as it shows that the glycemic profile is inadequate, start insulin at the standardized starting dose.
> If the fetus shows excessive growth, start insulin therapy VS continue monitoring, since the glycemic profile should change soon.
Follow-up interval: 7 to 10 days (assess adherence and possible hyperglycemia peaks).$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$r4b_insulina$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Scientific Rationale$LAUDO$, $LAUDO$According to the GDM treatment protocol in Brazil, adequate control is defined as at least 70% of values within target. In this case, [% na meta]% of glucose readings were within target, equal to or above the recommended 70% minimum. The glucometer memory DOES NOT CONFIRM adequate glycemic control: the actual glucose values indicate a risk to the fetus, since the patient is not fully adhering to treatment and presents hyperglycemia peaks in the glycemic profile.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_a$LAUDO$, $LAUDO$r4b_insulina$LAUDO$, $LAUDO$conduta$LAUDO$, 3, $LAUDO$Recommended Management$LAUDO$, $LAUDO$Start insulin therapy at a dose of [dose total de insulina]:
>> 2/3 in the morning: [dose manhã] and
>> 1/3 at 10 p.m. (bed time): [dose noite]
— Both subcutaneously —
Instruct on injection technique, care in the storage and transport of insulin, and signs of hypoglycemia.
Maintain the diet, physical activity, and daily 6-point glycemic monitoring — fasting, pre- and postprandial —, agreeing with the patient on 1-hour or 2-hour postprandial measurement.
Once insulin is introduced, MARI's active follow-up is discontinued.
Responsibility for the pregnant patient remains with the obstetrician (OB), whose obstetric glycemic targets always prevail.
Continued glycemic control may follow three arrangements, at the obstetrician's choice:
(1) the obstetrician themselves manages the dose adjustment, if confident to do so;
(2) collaboration with an endocrinologist, who makes the insulin dose adjustments without taking over the case; or
(3) referral to a specialized service, in the public system.
ATTENTION: Postpartum retesting: perform a 75g OGTT (fasting and 2h) between 6 and 8 weeks after delivery, to reclassify the glycemic status.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_b$LAUDO$, $LAUDO$4$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Scientific Rationale$LAUDO$, $LAUDO$Over the [dias preenchidos] days of monitoring with a 6-point profile, [% na meta]% of the measurements were within target. According to the GDM treatment protocol in Brazil, adequate control is defined as 70% or more of values within target. With the patient using insulin combined with diet and physical activity, and with adequate metabolic indicators (and ultrasound indicators, when possible), it is confirmed that the current therapeutic regimen is sufficient for glycemic control and should be maintained at this time.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_b$LAUDO$, $LAUDO$4$LAUDO$, $LAUDO$conduta$LAUDO$, 3, $LAUDO$Recommended Management$LAUDO$, $LAUDO$Maintain the current insulin dose ([dose atual de insulina]), diet, physical activity, and daily 6-point monitoring — fasting, post-breakfast, pre- and post-lunch, and pre- and post-dinner. Reinforce adherence to the meal plan, physical activity, and the insulin application and storage technique. Order an ultrasound to monitor fetal growth and amniotic fluid volume. The next follow-up should occur on [data do próximo retorno].
Follow-up interval: 15 days until 30 weeks; thereafter, 7 days until delivery.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_b$LAUDO$, $LAUDO$7$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Scientific Rationale$LAUDO$, $LAUDO$Patient [nome da paciente], using insulin, completed [dias preenchidos] days of monitoring with a 6-point profile, with [% na meta]% of the measurements within target. According to the GDM treatment protocol in Brazil, adequate control is defined as 70% or more of values within target. Even with insulin use, control remained inadequate — which indicates that the current insulin dose is insufficient and needs to be readjusted. Dose adjustment is outside the scope of MARI's automated guidance; therefore MARI's support ends at this point. Follow-up of gestational diabetes, however, must continue.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_b$LAUDO$, $LAUDO$7$LAUDO$, $LAUDO$conduta$LAUDO$, 3, $LAUDO$Recommended Management$LAUDO$, $LAUDO$The next step is the readjustment of the insulin dose (current: [dose atual de insulina]), according to the glycemic profile values. This adjustment can be conducted in three ways, depending on your confidence and the care setting: (1) by the obstetrician, if there is confidence to titrate the insulin; (2) in association with an endocrinologist; or (3) by referral to a specialized service (especially in the public system). Regardless of who conducts the adjustment, the targets that remain valid are the obstetric GDM targets: fasting below 95 mg/dL and 1-hour postprandial below 140 mg/dL and/or 2-hour below 120 mg/dL. Maintain daily 6-point monitoring, diet, and physical activity, and reinforce the insulin application technique and storage.$LAUDO$, 'publicado', 'en-US');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$ficha_c$LAUDO$, $LAUDO$2$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Scientific Rationale$LAUDO$, $LAUDO$Over the [dias preenchidos] days of monitoring, [% na meta]% of measurements were within target. According to the GDM treatment protocol in Brazil, adequate control is defined as 70% or more of values within target. In addition, the metabolic indicators (and the ultrasound indicators, when available) are also adequate, confirming that treatment with diet and exercise is being sufficient for glycemic control and, therefore, should be maintained.$LAUDO$, 'publicado', 'en-US');
