INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$gtt$LAUDO$, $LAUDO$8$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Justificación Científica$LAUDO$, $LAUDO$En la PTOG 75g realizada con [IG no GTT], la paciente [nome da paciente] presentó una glucemia en ayunas de [GTT jejum] mg/dL, de 1 hora de [GTT 1h] mg/dL y de 2 horas de [GTT 2h] mg/dL, confirmando Overt DM. Esta paciente TIENE Overt DM.$LAUDO$, 'publicado', 'es');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$gtt$LAUDO$, $LAUDO$8$LAUDO$, $LAUDO$conduta$LAUDO$, 3, $LAUDO$Conducta Orientativa$LAUDO$, $LAUDO$El tratamiento debe iniciarse inmediatamente, con adecuación nutricional individualizada, actividad física y monitorización diaria de la glucemia capilar, evaluando 4 puntos — en ayunas, posdesayuno, posalmuerzo y poscena. Las metas del control glucémico son: en ayunas por debajo de 95 mg/dL y posprandial de 1 hora menor que 140 mg/dL y/o de 2 horas menor que 120 mg/dL. El control adecuado reduce desenlaces maternos y fetales adversos. El diagnóstico oportuno y correcto salva vidas. NO espere. ¡NO repita el test! ¡TRATE!
Plazo de retorno: 7 a 10 días.$LAUDO$, 'publicado', 'es');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$gtt$LAUDO$, $LAUDO$negativo$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Justificación Científica$LAUDO$, $LAUDO$En la prueba de tolerancia a la glucosa realizada con [IG no GTT], la paciente [nome da paciente] presentó un valor en ayunas de [GTT jejum] mg/dL, de 1 hora de [GTT 1h] mg/dL y de 2 horas de [GTT 2h] mg/dL. De acuerdo con el protocolo diagnóstico de la DMG en Brasil, esos valores están por debajo de los respectivos puntos de corte y descartan el diagnóstico de DMG. CONCLUSIÓN: Esta paciente NO TIENE diabetes mellitus gestacional.$LAUDO$, 'publicado', 'es');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$gtt$LAUDO$, $LAUDO$negativo$LAUDO$, $LAUDO$conduta$LAUDO$, 3, $LAUDO$Conducta Orientativa$LAUDO$, $LAUDO$No hay indicación de tratamiento para el control de la hiperglucemia. La PTOG 75g normal a partir de las 24 semanas de gestación descarta el riesgo de DMG. Esta paciente no necesita ser investigada nuevamente para DMG en este embarazo y NO DEBE SER TRATADA. La PTOG 75g no debe repetirse en este embarazo. INVESTIGACIÓN DE LA DIABETES GESTACIONAL CERRADA.
Plazo de retorno: Sin retorno para el control de la hiperglucemia — solo control prenatal habitual (mensual hasta las 32 sem; cada 15 días hasta las 36 sem; semanal hasta el parto).$LAUDO$, 'publicado', 'es');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$retorno_1$LAUDO$, $LAUDO$1$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Justificación Científica$LAUDO$, $LAUDO$La paciente [nome da paciente], con [IG], presenta una glucemia en ayunas de [glicemia de jejum] mg/dL. 

De acuerdo con el protocolo diagnóstico de la DMG en Brasil, valores iguales o superiores a 92 mg/dL y menores que 126 mg/dL, en cualquier edad gestacional, confirman el diagnóstico de DMG. 

CONCLUSIÓN: ESTA PACIENTE TIENE DIABETES GESTACIONAL (DMG). No hay necesidad de otros exámenes para confirmar DMG.$LAUDO$, 'publicado', 'es');
