INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$retorno_1$LAUDO$, $LAUDO$8$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Justificación Científica$LAUDO$, $LAUDO$La paciente [nome da paciente] presenta una glucemia en ayunas de [glicemia de jejum] mg/dL. 

De acuerdo con el protocolo diagnóstico de la DMG en Brasil, valores iguales o superiores a 126 mg/dL confirman la diabetes diagnosticada por primera vez en la gestación (Overt DM). 

CONCLUSIÓN: Esta paciente TIENE diabetes diagnosticada en la gestación (Overt DM). No hay necesidad de otros exámenes para confirmar Overt DM.$LAUDO$, 'publicado', 'es');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
