INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$retorno_1$LAUDO$, $LAUDO$negativo$LAUDO$, $LAUDO$justificativa$LAUDO$, 2, $LAUDO$Justificación Científica$LAUDO$, $LAUDO$La paciente [nome da paciente] presenta una glucemia en ayunas de [glicemia de jejum] mg/dL, por debajo del punto de corte de 92 mg/dL. Esta paciente NO TIENE diabetes mellitus gestacional en este momento.$LAUDO$, 'publicado', 'es');
INSERT INTO public.laudo_textos (tipo_consulta, desfecho_clinico, bloco, ordem_bloco, titulo_bloco, texto, status, idioma)
VALUES ($LAUDO$retorno_1$LAUDO$, $LAUDO$negativo$LAUDO$, $LAUDO$conduta$LAUDO$, 3, $LAUDO$Conducta Orientativa$LAUDO$, $LAUDO$Como el rastreo inicial fue normal, la paciente debe realizar la prueba de tolerancia a la glucosa (PTOG 75g) entre la 24.ª y la 28.ª semana. Su PTOG 75g deberá hacerse entre [janela GTT início] y [janela GTT fim]. Mantenga el control prenatal habitual hasta la realización y el análisis del resultado de la PTOG.
Plazo de retorno: Sin retorno de control — la paciente regresa para la PTOG 75g en la ventana de 24 a 28 semanas.$LAUDO$, 'publicado', 'es');

